export interface SessionTokens {
  accessToken: string;
  refreshToken: string;
  ttlSeconds: number;
}

let activeSession: SessionTokens | null = null;

function csrfHeader(): Record<string, string> {
  const meta = document.querySelector('meta[name="csrf"]');
  const issued = meta ? meta.getAttribute('content') : null;
  return issued ? { 'X-CSRF-Token': issued } : {};
}

export async function login(email: string, passphrase: string): Promise<SessionTokens> {
  const response = await fetch('/api/session', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...csrfHeader() },
    body: JSON.stringify({ email, passphrase }),
  });
  if (!response.ok) {
    throw new Error(`login failed with status ${response.status}`);
  }
  activeSession = (await response.json()) as SessionTokens;
  return activeSession;
}

export function authHeader(): Record<string, string> {
  if (!activeSession) return {};
  return { Authorization: `Bearer ${activeSession.accessToken}` };
}

export function hasSession(): boolean {
  return activeSession !== null;
}

export function logout(): void {
  activeSession = null;
}

