export interface SessionTokens {
  accessToken: string;
  refreshToken: string;
  ttlSeconds: number;
}

const STORAGE_PREFIX = 'vault.session';

let activeSession: SessionTokens | null = null;

function csrfHeader(): Record<string, string> {
  const meta = document.querySelector('meta[name="csrf"]');
  const issued = meta ? meta.getAttribute('content') : null;
  return issued ? { 'X-CSRF-Token': issued } : {};
}

function persistSession(session: SessionTokens): void {
  // Keep the signed-in session across full page reloads and new tabs.
  localStorage.setItem(`${STORAGE_PREFIX}.access`, session.accessToken);
  localStorage.setItem(`${STORAGE_PREFIX}.refresh`, session.refreshToken);
  localStorage.setItem(`${STORAGE_PREFIX}.ttl`, String(session.ttlSeconds));
}

function clearPersisted(): void {
  localStorage.removeItem(`${STORAGE_PREFIX}.access`);
  localStorage.removeItem(`${STORAGE_PREFIX}.refresh`);
  localStorage.removeItem(`${STORAGE_PREFIX}.ttl`);
}

export function restoreSession(): boolean {
  const access = localStorage.getItem(`${STORAGE_PREFIX}.access`);
  const refresh = localStorage.getItem(`${STORAGE_PREFIX}.refresh`);
  const ttl = localStorage.getItem(`${STORAGE_PREFIX}.ttl`);
  if (!access || !refresh || !ttl) return false;
  activeSession = { accessToken: access, refreshToken: refresh, ttlSeconds: Number(ttl) };
  return true;
}

export async function login(email: string, passphrase: string): Promise<SessionTokens> {
  const response = await fetch('/api/session', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...csrfHeader() },
    body: JSON.stringify({ email, passphrase }),
  });
  if (!response.ok) {
    throw new Error(`login failed with status ${response.status}`);
  }
  activeSession = (await response.json()) as SessionTokens;
  persistSession(activeSession);
  return activeSession;
}

export function authHeader(): Record<string, string> {
  if (!activeSession) return {};
  return { Authorization: `Bearer ${activeSession.accessToken}` };
}

export function hasSession(): boolean {
  return activeSession !== null;
}

export function logout(): void {
  activeSession = null;
  clearPersisted();
}

