export interface ReportRow {
  region: string;
  units: number;
  revenue: number;
  cost: number;
}

export type ColumnFn = (row: ReportRow) => number;

const BUILTIN_COLUMNS: Record<string, ColumnFn> = {
  margin: (row) => row.revenue - row.cost,
  marginPct: (row) => (row.revenue === 0 ? 0 : (row.revenue - row.cost) / row.revenue),
  perUnit: (row) => (row.units === 0 ? 0 : row.revenue / row.units),
  spendRatio: (row) => (row.revenue === 0 ? 0 : row.cost / row.revenue),
};

export function builtinColumnNames(): string[] {
  return Object.keys(BUILTIN_COLUMNS);
}

export function resolveColumn(name: string): ColumnFn {
  const fn = BUILTIN_COLUMNS[name];
  if (!fn) {
    throw new Error(`unknown computed column: ${name}`);
  }
  return fn;
}

export function computeColumn(rows: ReportRow[], name: string): number[] {
  const fn = resolveColumn(name);
  return rows.map((row) => fn(row));
}

