export interface ReportRow {
  region: string;
  units: number;
  revenue: number;
  cost: number;
}

export type ColumnFn = (row: ReportRow) => number;

const BUILTIN_COLUMNS: Record<string, ColumnFn> = {
  margin: (row) => row.revenue - row.cost,
  marginPct: (row) => (row.revenue === 0 ? 0 : (row.revenue - row.cost) / row.revenue),
  perUnit: (row) => (row.units === 0 ? 0 : row.revenue / row.units),
  spendRatio: (row) => (row.revenue === 0 ? 0 : row.cost / row.revenue),
};

export function builtinColumnNames(): string[] {
  return Object.keys(BUILTIN_COLUMNS);
}

export function compileFormula(expression: string): ColumnFn {
  // Formulas come from the report builder's formula box, e.g. "revenue - cost * 1.2".
  const source = `const { region, units, revenue, cost } = row; return (${expression});`;
  return new Function('row', source) as ColumnFn;
}

export function resolveColumn(name: string, formulas: Record<string, string> = {}): ColumnFn {
  const fn = BUILTIN_COLUMNS[name];
  if (fn) return fn;
  const expression = formulas[name];
  if (!expression) {
    throw new Error(`unknown computed column: ${name}`);
  }
  return compileFormula(expression);
}

export function computeColumn(
  rows: ReportRow[],
  name: string,
  formulas: Record<string, string> = {},
): number[] {
  const fn = resolveColumn(name, formulas);
  return rows.map((row) => fn(row));
}

