export interface IntegrationListing {
  slug: string;
  title: string;
  vendor: string;
  landingPage: string;
}

const visitCounts = new Map<string, number>();

export function recordVisit(slug: string): number {
  const next = (visitCounts.get(slug) ?? 0) + 1;
  visitCounts.set(slug, next);
  return next;
}

export function visitCount(slug: string): number {
  return visitCounts.get(slug) ?? 0;
}

export function listingLabel(listing: IntegrationListing): string {
  return `${listing.title} — ${listing.vendor}`;
}

export function sortListings(listings: IntegrationListing[]): IntegrationListing[] {
  return [...listings].sort((a, b) => {
    const byVisits = visitCount(b.slug) - visitCount(a.slug);
    return byVisits !== 0 ? byVisits : a.title.localeCompare(b.title);
  });
}

export async function shareListing(listing: IntegrationListing): Promise<void> {
  await navigator.clipboard.writeText(listing.landingPage);
}

