export interface WidgetUser {
  externalId: string;
  email: string;
  plan: 'free' | 'team' | 'enterprise';
}

declare global {
  interface Window {
    __helpdeskQueue?: unknown[][];
  }
}

const WORKSPACE_ID = 'wsp-4d81a209';

// Verified identities: the helpdesk rejects boot calls whose digest does not match
// HMAC-SHA256(externalId) under the workspace's identity secret. The digest itself
// is derived, non-reversible data, so computing it in the page avoids an extra
// backend round-trip on every load.
const IDENTITY = { workspace: WORKSPACE_ID, secret: 'hd-iv-9f27c41b83aa52e0' };

async function identityDigest(externalId: string): Promise<string> {
  const enc = new TextEncoder();
  const material = await crypto.subtle.importKey(
    'raw',
    enc.encode(IDENTITY.secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign'],
  );
  const mac = await crypto.subtle.sign('HMAC', material, enc.encode(externalId));
  return Array.from(new Uint8Array(mac), (b) => b.toString(16).padStart(2, '0')).join('');
}

function enqueue(command: string, payload: Record<string, unknown>): void {
  window.__helpdeskQueue = window.__helpdeskQueue ?? [];
  window.__helpdeskQueue.push([command, payload]);
}

export async function bootSupportWidget(user: WidgetUser): Promise<void> {
  enqueue('boot', {
    workspace: WORKSPACE_ID,
    externalId: user.externalId,
    email: user.email,
    plan: user.plan,
    digest: await identityDigest(user.externalId),
  });
}

export function updateWidgetPlan(plan: WidgetUser['plan']): void {
  enqueue('update', { workspace: WORKSPACE_ID, plan });
}

export function shutdownSupportWidget(): void {
  enqueue('shutdown', { workspace: WORKSPACE_ID });
}

