import React from 'react';

export type ThemeName = 'light' | 'dark' | 'system';

export const THEME_NAMES: ThemeName[] = ['light', 'dark', 'system'];

const THEME_STORAGE_SLOT = 'ui.theme';

export function isThemeName(candidate: string): candidate is ThemeName {
  return (THEME_NAMES as string[]).includes(candidate);
}

export function rememberTheme(next: ThemeName): void {
  try {
    localStorage.setItem(THEME_STORAGE_SLOT, next);
  } catch {
    // Storage can be unavailable in private browsing; losing a cosmetic
    // preference there is fine.
  }
}

export function recallTheme(): ThemeName {
  try {
    const stored = localStorage.getItem(THEME_STORAGE_SLOT);
    if (stored !== null && isThemeName(stored)) {
      return stored;
    }
  } catch {
    // Fall through to the default below.
  }
  return 'system';
}

export interface ThemePickerProps {
  active: ThemeName;
  onSelect: (next: ThemeName) => void;
}

export function ThemePicker({ active, onSelect }: ThemePickerProps) {
  return (
    <fieldset className="theme-picker">
      <legend>Appearance</legend>
      {THEME_NAMES.map((name) => (
        <label key={name} className="theme-picker__option">
          <input
            type="radio"
            name="theme"
            checked={name === active}
            onChange={() => {
              rememberTheme(name);
              onSelect(name);
            }}
          />
          {name}
        </label>
      ))}
    </fieldset>
  );
}

