export interface ToastNotice {
  id: string;
  title: string;
  detail: string;
  tone: 'info' | 'success' | 'warning';
}

const MAX_VISIBLE = 4;

function noticeElement(notice: ToastNotice): HTMLElement {
  const item = document.createElement('li');
  item.className = `toast toast--${notice.tone}`;
  item.dataset.noticeId = notice.id;
  const heading = document.createElement('strong');
  heading.textContent = notice.title;
  const body = document.createElement('p');
  body.textContent = notice.detail;
  item.append(heading, body);
  return item;
}

export function dismissNotice(container: HTMLElement, noticeId: string): void {
  for (const child of Array.from(container.children)) {
    if (child instanceof HTMLElement && child.dataset.noticeId === noticeId) {
      child.remove();
    }
  }
