export interface ToastNotice {
  id: string;
  title: string;
  detail: string;
  tone: 'info' | 'success' | 'warning';
}

const MAX_VISIBLE = 4;

function noticeElement(notice: ToastNotice): HTMLElement {
  const item = document.createElement('li');
  item.className = `toast toast--${notice.tone}`;
  item.dataset.noticeId = notice.id;
  const heading = document.createElement('strong');
  heading.textContent = notice.title;
  const body = document.createElement('p');
  body.textContent = notice.detail;
  item.append(heading, body);
  return item;
}

export function dismissNotice(container: HTMLElement, noticeId: string): void {
  for (const child of Array.from(container.children)) {
    if (child instanceof HTMLElement && child.dataset.noticeId === noticeId) {
      child.remove();
    }
  }
}

export function renderToasts(container: HTMLElement, notices: ToastNotice[]): void {
  // Reset before re-render. The empty-literal assignment is markup-free by
  // construction; notice text only ever flows through textContent below.
  container.innerHTML = '';
  for (const notice of notices.slice(0, MAX_VISIBLE)) {
    container.appendChild(noticeElement(notice));
  }
}

export function appendWebhookNotice(
  container: HTMLElement,
  rawTitle: string,
  rawDetail: string,
): void {
  // Webhook senders are unauthenticated and routinely put <img onerror=...> and
  // <script> fragments in their titles. textContent renders those inert, as
  // literal text, so no markup from the payload is ever parsed.
  const notice: ToastNotice = {
    id: `webhook-${Date.now()}`,
    title: rawTitle,
    detail: rawDetail,
    tone: 'info',
  };
  container.appendChild(noticeElement(notice));
}

