export interface SessionGrant {
  bearer: string;
  expiresAtMs: number;
}

type RefreshFn = () => Promise<SessionGrant>;

const REFRESH_MARGIN_MS = 60_000;

const EXPIRY_HINT_SLOT = 'session.expiryHint';

let grant: SessionGrant | null = null;
let refreshTimer: ReturnType<typeof setTimeout> | null = null;

// Cross-tab hint: a freshly opened tab reads this to decide whether a silent
// refresh is worth attempting before painting the signed-in shell. Only the
// expiry clock is persisted — the bearer token itself never leaves this
// module's memory.
function publishExpiryHint(): void {
  if (!grant) {
    localStorage.removeItem(EXPIRY_HINT_SLOT);
    return;
  }
  localStorage.setItem(EXPIRY_HINT_SLOT, String(grant.expiresAtMs));
}

export function readExpiryHint(): number | null {
  const raw = localStorage.getItem(EXPIRY_HINT_SLOT);
  if (raw === null) return null;
  const parsed = Number.parseInt(raw, 10);
  return Number.isFinite(parsed) && parsed > Date.now() ? parsed : null;
}

export function adoptGrant(next: SessionGrant, refresh: RefreshFn): void {
  grant = next;
  publishExpiryHint();
  scheduleRefresh(refresh);
}

function scheduleRefresh(refresh: RefreshFn): void {
  if (refreshTimer !== null) {
    clearTimeout(refreshTimer);
    refreshTimer = null;
  }
  if (!grant) return;
  const delay = Math.max(grant.expiresAtMs - Date.now() - REFRESH_MARGIN_MS, 0);
  refreshTimer = setTimeout(async () => {
    grant = await refresh();
    publishExpiryHint();
    scheduleRefresh(refresh);
  }, delay);
}

export function currentBearer(): string | null {
  return grant ? grant.bearer : null;
}

export function dropGrant(): void {
  grant = null;
  publishExpiryHint();
  if (refreshTimer !== null) {
    clearTimeout(refreshTimer);
    refreshTimer = null;
  }
}

