import React from 'react';

export interface Profile {
  handle: string;
  bio: string;
  website: string | null;
  joinedYear: number;
}

function initialsFor(handle: string): string {
  const parts = handle.split(/[-_.]/).filter(Boolean);
  const letters = parts.slice(0, 2).map((part) => part.charAt(0));
  return letters.join('').toUpperCase() || handle.charAt(0).toUpperCase();
}

function shortenForDisplay(website: string): string {
  return website.replace(/^https?:\/\//, '').replace(/\/+$/, '');
}

function safeWebsiteHref(website: string): string | null {
  let parsed: URL;
  try {
    parsed = new URL(website);
  } catch {
    return null;
  }
  return parsed.protocol === 'https:' || parsed.protocol === 'http:' ? parsed.href : null;
}

export function ProfileCard({ profile }: { profile: Profile }) {
  const websiteHref = profile.website ? safeWebsiteHref(profile.website) : null;
  return (
    <section className="profile-card">
      <div className="profile-card__avatar" aria-hidden="true">
        {initialsFor(profile.handle)}
      </div>
      <h2 className="profile-card__handle">@{profile.handle}</h2>
      <p className="profile-card__bio">{profile.bio}</p>
      <dl className="profile-card__facts">
        <dt>Member since</dt>
        <dd>{profile.joinedYear}</dd>
        {profile.website && (
          <>
            <dt>Website</dt>
            <dd>
              {websiteHref ? (
                <a className="profile-card__website" href={websiteHref}>
                  {shortenForDisplay(profile.website)}
                </a>
              ) : (
                <span className="profile-card__website">{shortenForDisplay(profile.website)}</span>
              )}
            </dd>
          </>
        )}
      </dl>
    </section>
  );
}

