// Embedded checkout widget host page glue.
export function mountWidget(frame: HTMLIFrameElement, sessionToken: string) {
  frame.src = 'https://widget.example.com/checkout';
  frame.addEventListener('load', () => {
    frame.contentWindow?.postMessage({ type: 'session', sessionToken }, '*');
  });
  window.addEventListener('message', (e) => {
    if (e.data?.type === 'resize') {
      frame.style.height = `${e.data.height}px`;
    }
    if (e.data?.type === 'navigate') {
      window.location.href = e.data.url;
    }
  });
  return { frame, sessionToken };
}
